#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    const int MAX_S=20;
    long long dp[MAX_S+1];
    dp[0]=1; dp[1]=1;
    for(int i=2;i<=MAX_S;++i) dp[i]=dp[i-1]+dp[i-2];
    while(T--){
        int S; scanf("%d",&S);
        printf("%lld\n",dp[S]);
    }
    return 0;
}

